(() => {
  "use strict";

  const CONFIG = {
    // Waar injecten we de chart?
    SLOT_ID: "sizechart-slot",

    // GitHub Pages base
    BASE: "https://cpvb86.github.io/DDO/sizechart",

    // CSS (optioneel). Zet "" als je (nog) geen CSS gebruikt.
    CSS_PATH: "sizechart.min.css",

    // Charts map + fallback file
    CHARTS_DIR: "charts",
    DEFAULT_FILE: "default.html",

    // Widgets (optioneel via data-sizechart-widget="name")
    WIDGETS_DIR: "widgets",
    WIDGET_SUFFIX: ".v1.min.js",

    // Retry voor trage PDP rendering
    RETRIES: 25,
    RETRY_DELAY_MS: 200,

    // Bump bij elke release/update
    VERSION: "1.0.2",

    // Als je site SPA is (PDP zonder full reload), zet true
    SPA_MODE: false,

    DEBUG: false,
  };

  const log = (...a) => CONFIG.DEBUG && console.log("[sizechart]", ...a);
  const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

  // Append ?v=VERSION aan elke resource (CSS/HTML/JS widgets)
  const withVersion = (url) => {
    const sep = url.includes("?") ? "&" : "?";
    return `${url}${sep}v=${encodeURIComponent(CONFIG.VERSION)}`;
  };

  const slugify = (s) =>
    (s || "")
      .toLowerCase()
      .trim()
      .replace(/&/g, "and")
      .replace(/['"]/g, "")
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "");

  const escapeHtml = (s) =>
    String(s ?? "")
      .replaceAll("&", "&amp;")
      .replaceAll("<", "&lt;")
      .replaceAll(">", "&gt;")
      .replaceAll('"', "&quot;")
      .replaceAll("'", "&#39;");

  // Replace placeholders like {{brand}} in fetched HTML
  const applyPlaceholders = (html, brand) => {
    const safeBrand = (brand || "").trim() || "dit merk";
    const escapedBrand = escapeHtml(safeBrand);
    return String(html || "").replaceAll("{{brand}}", escapedBrand);
  };

  const findSlot = () => document.getElementById(CONFIG.SLOT_ID);

  const getBrand = () => {
    // <div itemprop="brand"><meta itemprop="name" content="Freya" /></div>
    const meta = document.querySelector('[itemprop="brand"] meta[itemprop="name"]');
    return meta?.getAttribute("content")?.trim() || "";
  };

  const ensureCss = () => {
    if (!CONFIG.CSS_PATH) return;
    if (document.querySelector('link[data-sizechart-css="1"]')) return;

    const href = withVersion(`${CONFIG.BASE}/${CONFIG.CSS_PATH}`);
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = href;
    link.setAttribute("data-sizechart-css", "1");
    document.head.appendChild(link);

    log("CSS linked:", href);
  };

  const fetchText = async (url) => {
    const res = await fetch(url, { credentials: "omit" });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return await res.text();
  };

  const chartUrl = (slug) =>
    withVersion(`${CONFIG.BASE}/${CONFIG.CHARTS_DIR}/${encodeURIComponent(slug || "default")}.html`);

  const defaultUrl = () =>
    withVersion(`${CONFIG.BASE}/${CONFIG.CHARTS_DIR}/${CONFIG.DEFAULT_FILE}`);

  const widgetUrl = (name) =>
    withVersion(
      `${CONFIG.BASE}/${CONFIG.WIDGETS_DIR}/${encodeURIComponent(name)}${CONFIG.WIDGET_SUFFIX}`
    );

  const loadWidgetOnce = (name) => {
    const key = `__ddoWidgetLoaded:${name}`;
    if (window[key]) return;
    window[key] = true;

    const s = document.createElement("script");
    s.async = true;
    s.src = widgetUrl(name);
    document.head.appendChild(s);

    log("Widget loaded:", name, s.src);
  };

  const runWidgetsInSlot = (slot) => {
    const nodes = slot.querySelectorAll("[data-sizechart-widget]");
    if (!nodes.length) return;

    nodes.forEach((n) => {
      const name = (n.getAttribute("data-sizechart-widget") || "").trim();
      if (name) loadWidgetOnce(name);
    });
  };

  const injectOnceKey = () => `__ddoSizechartInjected:${location.pathname}`;

  const inject = async () => {
    const key = injectOnceKey();
    if (window[key]) return;

    let slot = null;
    let brand = "";

    // Wacht op slot + (liefst) brand meta
    for (let i = 0; i < CONFIG.RETRIES; i++) {
      slot = findSlot();
      brand = getBrand();
      if (slot && brand) break;
      if (slot && i > Math.floor(CONFIG.RETRIES / 2)) break; // slot is er, brand niet => default mag
      await sleep(CONFIG.RETRY_DELAY_MS);
    }

    slot = findSlot();
    if (!slot) return;

    ensureCss();

    const slug = slugify(brand);

    // loading state (handig voor styling/CLS)
    slot.setAttribute("data-sizechart-loading", "1");

    try {
      const html = await fetchText(chartUrl(slug));
      slot.innerHTML = applyPlaceholders(html, brand);
      slot.setAttribute("data-sizechart-brand", slug || "default");
    } catch (e) {
      log("Primary chart failed, fallback:", e?.message || e);
      try {
        const html = await fetchText(defaultUrl());
        slot.innerHTML = applyPlaceholders(html, brand);
        slot.setAttribute("data-sizechart-brand", "default");
      } catch {
        slot.innerHTML = `<div><strong>Voor het merk ${escapeHtml(brand || "dit merk")} hebben we (nog) geen maattabel.</strong></div>`;
        slot.setAttribute("data-sizechart-brand", "default");
      }
    } finally {
      slot.removeAttribute("data-sizechart-loading");
      runWidgetsInSlot(slot);
      window[key] = true;
    }
  };

  // Optional SPA support
  const hookSpa = () => {
    const fire = () => inject();

    const wrap = (fnName) => {
      const orig = history[fnName];
      history[fnName] = function () {
        const ret = orig.apply(this, arguments);
        window.dispatchEvent(new Event("sizechart:routechange"));
        return ret;
      };
    };

    wrap("pushState");
    wrap("replaceState");
    window.addEventListener("popstate", () => window.dispatchEvent(new Event("sizechart:routechange")));
    window.addEventListener("sizechart:routechange", fire);
  };

  inject();
  if (CONFIG.SPA_MODE) hookSpa();
})();
